:ACoAAA1VgDkBgnIZQiaq9gGpZ-WVXzkP7zEDw5g", "peopleAlsoViewed/22/first_name": "Siriwat", "peopleAlsoViewed/22/follower_count": "275", "peopleAlsoViewed/22/headline": "IT Manager at Oriental Residence, Bangkok", "peopleAlsoViewed/22/last_name": "Tuncharoen", "peopleAlsoViewed/22/premium": "false", "peopleAlsoViewed/22/public_identifier": "siriwat-tuncharoen-221b0462", "peopleAlsoViewed/22/url": "https://linkedin.com/in/ACoAAA1VgDkBgnIZQiaq9gGpZ-WVXzkP7zEDw5g", "peopleAlsoViewed/23/entity_urn": "urn:li:fsd_profile:ACoAAAcyo9UBgrjHKHKgud8_3xTKFVhREfiqQZQ", "peopleAlsoViewed/23/first_name": "Elaine", "peopleAlsoViewed/23/follower_count": "891", "peopleAlsoViewed/23/headline": "Area General Manager - Indochina ", "peopleAlsoViewed/23/last_name": "Yue", "peopleAlsoViewed/23/premium": "false", "peopleAlsoViewed/23/profile_picture": "https://media.licdn.com/dms/image/v2/C5603AQETRYZAw1wiEA/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1516561337524?e=1778112000&v=beta&t=Yg-qCB0dYcnJG92IfjXPfsrKkLOjAhidyk92HK2iPtY", "peopleAlsoViewed/23/public_identifier": "elaine-yue-9b153734", "peopleAlsoViewed/23/url": "https://linkedin.com/in/ACoAAAcyo9UBgrjHKHKgud8_3xTKFVhREfiqQZQ", "peopleAlsoViewed/24/entity_urn": "urn:li:fsd_profile:ACoAAAHLeJ8BrAkPPm-hqC9WjCNEbQ1ykGnh9zo", "peopleAlsoViewed/24/first_name": "Kamaruddin", "peopleAlsoViewed/24/follower_count": "15", "peopleAlsoViewed/24/headline": "General Manager Hotel", "peopleAlsoViewed/24/last_name": "Baharin", "peopleAlsoViewed/24/premium": "false", "peopleAlsoViewed/24/public_identifier": "kamaruddin-baharin-a53101a", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAAAHLeJ8BrAkPPm-hqC9WjCNEbQ1ykGnh9zo", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAACB_yCABII8HSRZqT2RXcvktDBp1AMkru5U", "peopleAlsoViewed/25/first_name": "Marc", "peopleAlsoViewed/25/follower_count": "1518", "peopleAlsoViewed/25/headline": "General Manager at Shinta Mani Wild", "peopleAlsoViewed/25/last_name": "LeBlanc", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/D4E03AQGWjiuwWxgqOQ/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1722265385643?e=1778112000&v=beta&t=toILdJioRKvVDLm7k05AmuzebSiLC1u71RwCibG2-3s", "peopleAlsoViewed/25/public_identifier": "marc-leblanc-514727132", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAACB_yCABII8HSRZqT2RXcvktDBp1AMkru5U", "profilePic": "https://media.licdn.com/dms/image/v2/D5603AQF8Tx3k1Kzl8w/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1732763302732?e=1778112000&v=beta&t=P7fRJbbryGdWQla-QjrlGfggSijoSXo_wpzwU6Yz9Bc", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/D5603AQF8Tx3k1Kzl8w/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1732763302732?e=1778112000&v=beta&t=P7fRJbbryGdWQla-QjrlGfggSijoSXo_wpzwU6Yz9Bc", "publicIdentifier": "ewan-taylor-60404661", "recommendations/0/context": "Ewan managed Sochea directly", "recommendations/0/date": "December 24, 2024", "recommendations/0/description": "Sochea, or my pocket rocket, as I named her, was up there with the best Sales Directors I have been lucky enough to work with. Sochea can pick up the phone to a number of senior travel agents, DMCs and key bookers and action her tasks professionally and in quick time, her connections are admirable!  Other notable skills which make her an asset to any hotel include; budgeting, administrative abilities and loyalty. With a personality that is always cheerful combined with her reliability and in-depth industry knowledge, I without question can recommend Sochea!", "recommendations/0/name": "Sochea Uon", "recommendations/0/subtitle": "Director of Sales / Shinta Mani Angkor / Bensley Collection Pool Villas", "recommendations/0/url": "https://www.linkedin.com/in/sochea-uon-688b4834/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAAdJwcgB6Ky7YRrf-uP1EdB7lFH7NGNcOGM", "recommendations/1/context": "Ewan worked with David on the same team", "recommendations/1/date": "May 29, 2024", "recommendations/1/description": "David is an honest and reliable gentleman extraordinaire! His team adored him and would move heaven and earth for him, which speaks volumes about his caring nature.  David's love for nature and wildlife made him a perfect fit as GM in the jungles of Cambodia. His sharp wit and infectious laughter will be missed. It would be a delight to be able to work with David in some capacity again in the future.", "recommendations/1/name": "David Steyn", "recommendations/1/subtitle": "General manager, Wild Hill - Collection in the Wild", "recommendations/1/url": "https://www.linkedin.com/in/david-steyn-b30a5b55/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAAu5bZQBoNZHCcbiWT4O0GlpHPOknYHheg8", "recommendations/2/context": "Ewan worked with Brian but they were at different companies", "recommendations/2/date": "February 1, 2024", "recommendations/2/description": "Brian Norris is a hardworking, reliable and honest hotelier. His experience in sales and operations has made him a well sought after professional who I would happily recommend.", "recommendations/2/name": "Brian Norris, CHM", "recommendations/2/subtitle": "Specializing in Customer Service, Revenue and E Commerce", "recommendations/2/url": "https://www.linkedin.com/in/brian-norris-chm-7742a9b0/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAABeJQwgByEbuMP6uOtIZFtjAWiopkLZ3Vt0", "recommendations/3/context": "Ewan managed Yega directly", "recommendations/3/date": "October 27, 2020", "recommendations/3/description": "Working with Yega made my life as his hotel GM as smooth as silk. Only once he left for a fantastic offer did I realise this... \n\nThere are many outstanding qualities that Yega possesses, but to narrow down to core attributes I would not hesitate to recommend to any GM or such property leader Yega for his ability to remain calm in stressful situations, his financial astuteness as well as his understanding of the inside out of daily operations. Yega was respected by both staff and guests and created a strong return business from local diners. \n\nAny business would be lucky to have Yega work with them. I am happy to be contacted for further information with regards to Yega. ", "recommendations/3/name": "Yega Thiyagarajan", "recommendations/3/subtitle": "Hospitality Leader | Hotel Pre-Opening & Boutique Hotel Specialist | From Concept to Profitable Operations", "recommendations/3/url": "https://www.linkedin.com/in/yega-thiyagarajan-6762a126/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAAVhrHoBAehWrHKBUxUlOCCjkgXWpmlKl8U", "recommendations/4/context": "Oliver was senior to Ewan but didn't manage Ewan directly", "recommendations/4/date": "November 24, 2016", "recommendations/4/description": "\nI have managed the Villa Samadhi hotel under the control of Mr Maynard’s financial leadership and found Mr Maynard to be a very competent and ethical financial manager and I can highly recommend him in such a capacity. \nHe is able to analyse a situation thoroughly and implement accordingly, new strategies to streamline and improve the daily operations of the business and he has also proved to be a responsible and personable colleague\n In addition, Mr Maynard is very approachable for any team member to bring forth any issues they have and assist / train them where necessary. \n \nEwan Taylor, Hotel Manager, Villa Samadhi, Kuala Lumpur, Malaysia\n", "recommendations/4/name": "Oliver M.", "recommendations/4/subtitle": "Finance Manager at Bristol City Council", "recommendations/4/url": "https://www.linkedin.com/in/oliver-maynard/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAF55_IBvGO1dYQfSNp8ipBTch1YMO3sp20", "recommendations/5/context": "Ewan was senior to Chef Ken  but didn't manage Chef Ken  directly", "recommendations/5/date": "October 20, 2015", "recommendations/5/description": "Kantapat (Ken) was part of the set up team at the Kebaya restaurant which was recently awarded a place on Asia's top 25 fine dining restaurants. Ken was a wonderful colleague to work with for 3 years, a very talented chef as well as a happy person to be around. Ken looks at cooking as an art and he is a very accomplished and passionate artist.I am confident that Ken will have a very successful future and can highly recommend him. ", "recommendations/5/name": "Chef Ken  Kantapat", "recommendations/5/subtitle": "Chef & Owner @ S.Ken's bistro Kao Tao", "recommendations/5/url": "https://www.linkedin.com/in/chef-ken-kantapat-b912a745/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAAAl5x90ByMxueAPc6c6Us5MBvtUe7LlZZmY", "recommendationsReceived/0/context": "Lee worked with Ewan on the same team", "recommendationsReceived/0/date": "March 10, 2024", "recommendationsReceived/0/description": "I have had the privilege of working closely with Ewan for the last 2 years and in that time, have come to know his as a dedicated and talented individual.    Ewan's passion for his work is inspiring.  He exudes enthusiasm, professionalism and a commitment to excellence that is evidence in all that he does, with meticulous attention to detail.  \n\nEwan has displayed his ability to collaborate effectively with diverse team and to navigate complex challenges.  He fosters an inclusive and supportive work environment where people ae valued and heard.  His clear communication skills and natural leadership qualities make him a trusted and respected colleague.\n\nIn addition to his professional skills, Ewan is also a person of integrity and character; honest and reliable with a genuine concern for others.  His positive attitude and infectious enthusiasm make him a pleasure to work with.  \n\nI wish Ewan continued success for the future and would welcome the opportunity and privilege to work with him again.", "recommendationsReceived/0/name": "Lee Sutton", "recommendationsReceived/0/subtitle": "Owner, Dynamic PR & Events", "recommendationsReceived/0/url": "https://www.linkedin.com/in/lee-sutton-14b72416/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAANPccsBJA9AQiswugHztf2O53n4Fnc9Wr8", "recommendationsReceived/1/context": "Jason M. managed Ewan directly", "recommendationsReceived/1/date": "March 7, 2024", "recommendationsReceived/1/description": "Subject: Professional Reference for Mr. Ewan Taylor\n\nI am delighted to provide a professional reference for Mr. Ewan Taylor, with whom I had the privilege of working for over two years. Initially, I recruited Ewan to assist in the establishment and development of a private island resort off the coast of Cambodia. Although that project experienced delays, we were fortunate enough to transition Ewan to our flagship property, Shinta Mani Angkor, in Siem Reap.\nUnder his leadership, Shinta Mani Angkor experienced the best financial performance in its 20-year history, a remarkable achievement considering the challenging circumstances of the ongoing pandemic. Notably, Ewan was instrumental in leading our brand upgrade, elevating the hotel's ranking to #15 on Trip Advisor from a previous position of #75.\n\nIn addition to these accomplishments, Ewan also played a key role in the creation and implementation of several brand-defining product upgrades and new offerings. A noteworthy example is the development of Kroya - Modern Cambodian Cuisine. This restaurant, under his guidance, achieved the #1 status on Trip Advisor, a highly commendable feat in a competitive market.\n\nEwan's vibrant personality and infectious energy greatly contributed to creating a positive and enjoyable work environment. His interactions with both staff and guests consistently radiated positivity, making every encounter with him a genuinely pleasing experience.\n\nWorking with Ewan over the past years has been a true pleasure. I greatly appreciate his dedication, outgoing nature, and consistently positive attitude. It is with both personal satisfaction and professional confidence that I wholeheartedly endorse Ewan Taylor for any position or endeavor he may pursue in the future. His contributions to our organization have been invaluable, and I am certain he will continue to make a significant impact wherever his career takes him.", "recommendationsReceived/1/name": "Jason M. Friedman", "recommendationsReceived/1/subtitle": "J.M. Friedman Hospitality", "recommendationsReceived/1/url": "https://www.linkedin.com/in/jasonfriedman/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAD0XDQBx_CuY2rNVymur4bhmGQjFymkbCk", "recommendationsReceived/2/context": "Buddhachard was senior to Ewan but didn't manage Ewan directly", "recommendationsReceived/2/date": "June 5, 2020", "recommendationsReceived/2/description": "It's rare that you come across standout talent like Ewan. I had the pleasure of working with Ewan for three years at Cross Hotels & Resorts, opening and operating the award-winning X2 Chiang Mai Riverside. I was particularly impressed by Ewan's ability to build the strongest opening team. That skill often takes years to develop among general managers, but it seemed to come perfectly naturally to him. Ewan and his superstar team brought the brand new hotel to Number One ranking out of more than 500 hotels in the region in the first year of operation and has stayed on top since. As a team member or a leader, Ewan earns my highest recommendation.", "recommendationsReceived/2/name": "Buddhachard P.", "recommendationsReceived/2/subtitle": "SONO Hotels & Resorts Asia - Vice President Marketing", "recommendationsReceived/2/url": "https://www.linkedin.com/in/buddhachard-paengchai/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAABDXlWoBj3G_ySbAhmAFcun0lwp7gCfaU10", "recommendationsReceived/3/context": "James worked with Ewan on the same team", "recommendationsReceived/3/date": "May 29, 2020", "recommendationsReceived/3/description": "Ewan is an excellent colleague and a very hands on GM. His level of professionalism, under taking of responsibilities and judgment calls towards the business of his industry is one of the greatest assets. A testiment of a true leader is what Ewan is and is liked by all his guests and his entire team! ", "recommendationsReceived/3/name": "James H.", "recommendationsReceived/3/subtitle": "General Manager - Away Chiang Mai Thapae Resort at CROSS Hotels & Resorts", "recommendationsReceived/3/url": "https://www.linkedin.com/in/james-h-838b669/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAHF5ywBb11wZoIIUiuN41126TOXIMaep1w", "recommendationsReceived/4/context": "Paul was senior to Ewan but didn't manage Ewan directly", "recommendationsReceived/4/date": "May 29, 2020", "recommendationsReceived/4/description": "Ewan has an impressive skill of merging old school principles of leadership with new which is rare in this day and age. While working with Ewan I witnessed him lead his team to the number one ranked luxury hotel in the region and more notable he maintained this position! Ewan is a thought leader and beyond his peers in driving sustainability, creativity and innovation through the hotels that he runs. Commercially Ewan is extremely strong and has an impressive long range lens on the continual improvement of his properties digital strategies. Ewan is a pleasure to work with and has an uncanny skill of speaking his mind all while maintaining a good sense of humor.", "recommendationsReceived/4/name": "Paul Wilson", "recommendationsReceived/4/subtitle": "Vice President of Amadeus Hospitality - Asia Pacific", "recommendationsReceived/4/url": "https://www.linkedin.com/in/wilsonpaul16/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAFa-wsBmVx4V4Wdb_kAuAFz5yrzbbYggQk", "recommendationsReceived/5/context": "Oliver was senior to Ewan but didn't manage Ewan directly", "recommendationsReceived/5/date": "April 3, 2017", "recommendationsReceived/5/description": "I worked in the same hotel and restaurant group as Ewan for 10 months. As soon as I met Ewan it was obvious that he was a knowledgeable and friendly person with a can-do and professional attitude. \nHe is a passionate manager who will push to get what he needs to best serve the group’s guests, yet at those times where the company cannot provide, he will gracefully accept, and as such he carefully preserves the good relationships that are so important to being a good manager. \nIn our weekly management meetings he was always able to put forward suggestions to issues raised by others, and was able to do so in a way that would encourage other managers to look at the issue in a fresh way.\nI would be happy to be a colleague of Ewan’s again in future.\n", "recommendationsReceived/5/name": "Oliver M.", "recommendationsReceived/5/subtitle": "Finance Manager at Bristol City Council", "recommendationsReceived/5/url": "https://www.linkedin.com/in/oliver-maynard/", "recommendationsReceived/5/urn": "urn:li:fsd_profile:ACoAAAF55_IBvGO1dYQfSNp8ipBTch1YMO3sp20", "recommendationsReceived/6/context": "Dilip Bajra Singh reported directly to Ewan", "recommendationsReceived/6/date": "February 14, 2017", "recommendationsReceived/6/description": "My personal few words about my General Manager,\n\nI have worked with my GM ( Mr. Ewan Taylor ) from 15 nov 2012 to Feb 2016 at Seven Terraces hotel, George Town, Penang, Malaysia.\n\nI would say He really is a very loving wonderful person with a very good heart, He is very hard working, intelligent, smart and very kind, He is filled with lot of capabilities with great ideas of running the hotel business.\n\nHe handled his guests with the TOP most high quality standard, A class service that was the reason the hotel was No-1 in trip advisor with very high ranking and good reviews in agoda.com, booking.com etc during his period in Seven terraces, He is very good in handling any kind of guest even the most difficult person would be happy and satisfied after having some few words with him.he is master in hotel business running job.\n\nDuring my service in seven terraces with him was really a very great time, I have learned a lot of knowledge working with him and his way of teaching and handling the hotel staff was excellent and Super, He is a very caring and understanding G.M. He is a person who knows how to take care of his staff, I am missing him a lot.\n\nHe Will always be in my heart love you Mr. Ewan Sir.\n", "recommendationsReceived/6/name": "Dilip Bajra Singh Lama", "recommendationsReceived/6/subtitle": "Company Owner at Bomzan Store Pvt. Ltd", "recommendationsReceived/6/url": "https://www.linkedin.com/in/dilip-bajra-singh-lama-58b96b77/", "recommendationsReceived/6/urn": "urn:li:fsd_profile:ACoAABBWj3sB7sU2tHjXsF3gZ33JDORZIqOIcXU", "recommendationsReceived/7/context": "Chef Ken  reported directly to Ewan", "recommendationsReceived/7/date": "November 4, 2016", "recommendationsReceived/7/description": "    I am pleased to write this recommendation for Mr. Taylor. He was my  GM  in my previous job at 7 terraces hotel in Penang and I personally known him for more than 3 years.\n   Mr.Taylor was always a good role model for his staffs and colleagues. He is an exceptional leader who combines his practical abitlities with his willingness to guide all the staffs to achive the success goal of the company. He always works hard to earn success and good results. With good leader and manging skill I am sure where ever he works he will bring success to those company with out the doubt.\n    ", "recommendationsReceived/7/name": "Chef Ken  Kantapat", "recommendationsReceived/7/subtitle": "Chef & Owner @ S.Ken's bistro Kao Tao", "recommendationsReceived/7/url": "https://www.linkedin.com/in/chef-ken-kantapat-b912a745/", "recommendationsReceived/7/urn": "urn:li:fsd_profile:ACoAAAl5x90ByMxueAPc6c6Us5MBvtUe7LlZZmY", "recommendationsReceived/8/context": "Ma. Clara Jesusa worked with Ewan on the same team", "recommendationsReceived/8/date": "November 3, 2016", "recommendationsReceived/8/description": "Ewan works with passion. He develops people and enourages them to perform. He has superb customer service and is doing it with sincerity. To colleagues, he is very supportive and is always willing to share knowledge. ", "recommendationsReceived/8/name": "Ma. Clara Jesusa Guzman", "recommendationsReceived/8/subtitle": "Author. Hotelier. Trainer.", "recommendationsReceived/8/url": "https://www.linkedin.com/in/ma-clara-jesusa-guzman-93303423/", "recommendationsReceived/8/urn": "urn:li:fsd_profile:ACoAAATPQzcBEod849hgnurNf6XTWAYKaDiJQwc", "recommendationsReceived/9/context": "Yega reported directly to Ewan", "recommendationsReceived/9/date": "November 3, 2016", "recommendationsReceived/9/description": "I had the pleasure of working under Ewan at The 7 Terraces in Georgetown, Penang. I was with him during the pre-opening stages and his professional leadership, calm demeanor and strong management skills ensured that the hotel opened on time and was a resounding success from day 1 of operations, until present day. He is a hands on hotel operator and is very generous with his knowledge. It was his patience and nurturing disposition that allowed me to pursue my own career objectives and he was instrumental in guiding me on my future career choices. If I ever had an opportunity to work with him again, I would not hesitate. ", "recommendationsReceived/9/name": "Yega Thiyagarajan", "recommendationsReceived/9/subtitle": "Hospitality Leader | Hotel Pre-Opening & Boutique Hotel Specialist | From Concept to Profitable Operations", "recommendationsReceived/9/url": "https://www.linkedin.com/in/yega-thiyagarajan-6762a126/", "recommendationsReceived/9/urn": "urn:li:fsd_profile:ACoAAAVhrHoBAehWrHKBUxUlOCCjkgXWpmlKl8U", "skills/0/title": "Strategy", "skills/1/title": "Team Management", "skills/2/title": "Leadership Development", "skills/3/title": "Interpersonal Skills", "skills/4/title": "Talent Management", "skills/5/title": "Team Leadership", "skills/6/title": "Sustainable Tourism", "skills/7/t